contracts/KortanaFactory.sol.content:
// SPDX-License-Identifier: GPL-2.0-or-later
pragma solidity ^0.8.20;

/**
 * @title KortanaFactory
 * @notice Deploys KortanaSwap pools and manages protocol ownership
 * @dev Uniswap V3 style factory with concentrated liquidity pools
 *
 * Supported Fee Tiers:
 * → 100   (0.01%) — Stable pairs (DNRS/USDT)
 * → 500   (0.05%) — Correlated pairs
 * → 3000  (0.30%) — Standard pairs (DNR/USDT, DNR/DNRS)
 * → 10000 (1.00%) — Exotic pairs
 *
 * Kortana Chains:
 * → Testnet: 72511
 * → Mainnet: 9002
 */

import "./interfaces/IKortanaFactory.sol";
import "./KortanaPoolDeployer.sol";
import "./NoDelegateCall.sol";
import "./interfaces/IKortanaPool.sol";

contract KortanaFactory is IKortanaFactory, KortanaPoolDeployer, NoDelegateCall {

    // ============================================================
    // STATE
    // ============================================================

    address public override owner;
    address public override feeCollector; // Kortana Foundation treasury

    // feeAmountTickSpacing: fee => tickSpacing
    mapping(uint24 => int24) public override feeAmountTickSpacing;

    // getPool: token0 => token1 => fee => poolAddress
    mapping(address => mapping(address => mapping(uint24 => address)))
        public override getPool;

    // All deployed pools
    address[] public allPools;

    // Protocol fee: numerator/denominator (max 10%)
    uint8 public override feeProtocol; // default 0, max 10

    // ============================================================
    // CONSTRUCTOR
    // ============================================================

    constructor(address _feeCollector) {
        owner = msg.sender;
        feeCollector = _feeCollector;
        emit OwnerChanged(address(0), msg.sender);

        // Initialize fee tiers
        _enableFeeAmount(100, 1);       // 0.01% — tick spacing 1
        _enableFeeAmount(500, 10);      // 0.05% — tick spacing 10
        _enableFeeAmount(3000, 60);     // 0.30% — tick spacing 60
        _enableFeeAmount(10000, 200);   // 1.00%  — tick spacing 200
    }

    // ============================================================
    // POOL CREATION
    // ============================================================

    /**
     * @notice Creates a new pool for the given token pair and fee tier
     * @dev tokenA and tokenB may be passed in either order
     * @param tokenA First token of the pair
     * @param tokenB Second token of the pair
     * @param fee Fee tier for the pool
     * @return pool Address of the created pool
     */
    function createPool(
        address tokenA,
        address tokenB,
        uint24 fee
    ) external override noDelegateCall returns (address pool) {
        require(tokenA != tokenB, "KortanaFactory: IDENTICAL_ADDRESSES");
        (address token0, address token1) = tokenA < tokenB
            ? (tokenA, tokenB)
            : (tokenB, tokenA);
        require(token0 != address(0), "KortanaFactory: ZERO_ADDRESS");
        require(feeAmountTickSpacing[fee] != 0, "KortanaFactory: FEE_NOT_ENABLED");
        require(
            getPool[token0][token1][fee] == address(0),
            "KortanaFactory: POOL_EXISTS"
        );

        int24 tickSpacing = feeAmountTickSpacing[fee];
        pool = deploy(address(this), token0, token1, fee, tickSpacing);

        getPool[token0][token1][fee] = pool;
        getPool[token1][token0][fee] = pool;
        allPools.push(pool);

        emit PoolCreated(token0, token1, fee, tickSpacing, pool);
    }

    // ============================================================
    // ADMIN
    // ============================================================

    function setOwner(address _owner) external override {
        require(msg.sender == owner, "KortanaFactory: NOT_OWNER");
        emit OwnerChanged(owner, _owner);
        owner = _owner;
    }

    function setFeeCollector(address _feeCollector) external {
        require(msg.sender == owner, "KortanaFactory: NOT_OWNER");
        feeCollector = _feeCollector;
    }

    function enableFeeAmount(uint24 fee, int24 tickSpacing) external override {
        require(msg.sender == owner, "KortanaFactory: NOT_OWNER");
        _enableFeeAmount(fee, tickSpacing);
    }

    function _enableFeeAmount(uint24 fee, int24 tickSpacing) internal {
        require(fee < 1000000, "KortanaFactory: FEE_TOO_LARGE");
        require(tickSpacing > 0 && tickSpacing < 16384, "KortanaFactory: INVALID_TICK_SPACING");
        require(feeAmountTickSpacing[fee] == 0, "KortanaFactory: FEE_ALREADY_ENABLED");
        feeAmountTickSpacing[fee] = tickSpacing;
        emit FeeAmountEnabled(fee, tickSpacing);
    }

    function setFeeProtocol(uint8 _feeProtocol) external {
        require(msg.sender == owner, "KortanaFactory: NOT_OWNER");
        require(_feeProtocol <= 10, "KortanaFactory: PROTOCOL_FEE_TOO_HIGH");
        feeProtocol = _feeProtocol;
        emit SetFeeProtocol(feeProtocol, _feeProtocol);
    }

    function allPoolsLength() external view returns (uint256) {
        return allPools.length;
    }

    function collectProtocol(
        address pool,
        address recipient,
        uint128 amount0Requested,
        uint128 amount1Requested
    ) external returns (uint128 amount0, uint128 amount1) {
        require(msg.sender == owner, "KortanaFactory: NOT_OWNER");
        return IKortanaPool(pool).collectProtocol(
            recipient,
            amount0Requested,
            amount1Requested
        );
    }
}

contracts/KortanaPool.sol.content:
// SPDX-License-Identifier: GPL-2.0-or-later
pragma solidity ^0.8.20;

/**
 * @title KortanaPool
 * @notice Individual liquidity pool — the core of KortanaSwap
 * @dev Implements concentrated liquidity (Uniswap V3 model)
 */

import "./interfaces/IKortanaPool.sol";
import "./interfaces/IKortanaFactory.sol";
import "./interfaces/IKortanaPoolDeployer.sol";
import "./interfaces/IKortanaMintCallback.sol";
import "./interfaces/IKortanaSwapCallback.sol";
import "./interfaces/IKortanaFlashCallback.sol";

import "./libraries/TickMath.sol";
import "./libraries/Position.sol";
import "./libraries/Oracle.sol";
import "./libraries/FullMath.sol";
import "./libraries/SqrtPriceMath.sol";
import "./libraries/SwapMath.sol";
import "./libraries/LiquidityMath.sol";
import "./libraries/SafeCast.sol";
import "./libraries/Tick.sol";
import "./libraries/TickBitmap.sol";
import "./libraries/FixedPoint128.sol";
import "./NoDelegateCall.sol";

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract KortanaPool is IKortanaPool, ReentrancyGuard, NoDelegateCall {
    using SafeCast for uint256;
    using SafeCast for uint128;
    using SafeCast for int256;
    using Tick for mapping(int24 => Tick.Info);
    using TickBitmap for mapping(int16 => uint256);
    using Position for mapping(bytes32 => Position.Info);
    using Position for Position.Info;
    using Oracle for Oracle.Observation[65535];

    // ============================================================
    // IMMUTABLES
    // ============================================================
    address public immutable override factory;
    address public immutable override token0;
    address public immutable override token1;
    uint24 public immutable override fee;
    int24 public immutable override tickSpacing;
    uint128 public immutable override maxLiquidityPerTick;

    // ============================================================
    // STATE — SLOT 0
    // ============================================================
    struct Slot0 {
        uint160 sqrtPriceX96;   // current price as sqrt(ratio) Q64.96
        int24 tick;             // current tick
        uint16 observationIndex;
        uint16 observationCardinality;
        uint16 observationCardinalityNext;
        uint8 feeProtocol;
        bool unlocked;
    }
    Slot0 public override slot0;

    // ============================================================
    // STATE — FEES
    // ============================================================
    uint256 public override feeGrowthGlobal0X128;
    uint256 public override feeGrowthGlobal1X128;

    // Protocol fees accumulated
    struct ProtocolFees {
        uint128 token0;
        uint128 token1;
    }
    ProtocolFees public override protocolFees;

    // ============================================================
    // STATE — LIQUIDITY
    // ============================================================
    uint128 public override liquidity;

    // ============================================================
    // STATE — MAPPINGS
    // ============================================================
    mapping(int24 => Tick.Info) public override ticks;
    mapping(int16 => uint256) public override tickBitmap;
    mapping(bytes32 => Position.Info) public override positions;
    Oracle.Observation[65535] public override observations;

    // ============================================================
    // MODIFIERS
    // ============================================================
    modifier lock() {
        require(slot0.unlocked, "KortanaPool: LOCKED");
        slot0.unlocked = false;
        _;
        slot0.unlocked = true;
    }

    modifier onlyFactoryOwner() {
        require(
            msg.sender == IKortanaFactory(factory).owner(),
            "KortanaPool: NOT_FACTORY_OWNER"
        );
        _;
    }

    // ============================================================
    // CONSTRUCTOR
    // ============================================================
    constructor() {
        int24 _tickSpacing;
        (factory, token0, token1, fee, _tickSpacing) = IKortanaPoolDeployer(msg.sender).parameters();
        tickSpacing = _tickSpacing;
        maxLiquidityPerTick = Tick.tickSpacingToMaxLiquidityPerTick(_tickSpacing);
    }

    // ============================================================
    // INITIALIZE
    // ============================================================

    function initialize(uint160 sqrtPriceX96) external override {
        require(slot0.sqrtPriceX96 == 0, "KortanaPool: ALREADY_INITIALIZED");

        int24 tick = TickMath.getTickAtSqrtRatio(sqrtPriceX96);

        (uint16 cardinality, uint16 cardinalityNext) = observations.initialize(
            _blockTimestamp()
        );

        slot0 = Slot0({
            sqrtPriceX96: sqrtPriceX96,
            tick: tick,
            observationIndex: 0,
            observationCardinality: cardinality,
            observationCardinalityNext: cardinalityNext,
            feeProtocol: 0,
            unlocked: true
        });

        emit Initialize(sqrtPriceX96, tick);
    }

    // ============================================================
    // MINT — ADD LIQUIDITY
    // ============================================================

    function mint(
        address recipient,
        int24 tickLower,
        int24 tickUpper,
        uint128 amount,
        bytes calldata data
    ) external override lock noDelegateCall returns (uint256 amount0, uint256 amount1) {
        require(amount > 0, "KortanaPool: ZERO_AMOUNT");

        (, int256 amount0Int, int256 amount1Int) = _updatePosition(
            recipient,
            tickLower,
            tickUpper,
            amount.toInt128(),
            slot0.tick
        );

        amount0 = uint256(amount0Int);
        amount1 = uint256(amount1Int);

        uint256 balance0Before;
        uint256 balance1Before;

        if (amount0 > 0) balance0Before = _balance0();
        if (amount1 > 0) balance1Before = _balance1();

        IKortanaMintCallback(msg.sender).kortanaMintCallback(amount0, amount1, data);

        if (amount0 > 0) {
            require(
                balance0Before + amount0 <= _balance0(),
                "KortanaPool: M0"
            );
        }
        if (amount1 > 0) {
            require(
                balance1Before + amount1 <= _balance1(),
                "KortanaPool: M1"
            );
        }

        emit Mint(msg.sender, recipient, tickLower, tickUpper, amount, amount0, amount1);
    }

    // ============================================================
    // COLLECT — WITHDRAW FEES
    // ============================================================

    function collect(
        address recipient,
        int24 tickLower,
        int24 tickUpper,
        uint128 amount0Requested,
        uint128 amount1Requested
    ) external override lock returns (uint128 amount0, uint128 amount1) {
        bytes32 key = keccak256(abi.encodePacked(msg.sender, tickLower, tickUpper));
        Position.Info storage position = positions[key];

        amount0 = amount0Requested > position.tokensOwed0
            ? position.tokensOwed0
            : amount0Requested;
        amount1 = amount1Requested > position.tokensOwed1
            ? position.tokensOwed1
            : amount1Requested;

        if (amount0 > 0) {
            position.tokensOwed0 -= amount0;
            IERC20(token0).transfer(recipient, amount0);
        }
        if (amount1 > 0) {
            position.tokensOwed1 -= amount1;
            IERC20(token1).transfer(recipient, amount1);
        }

        emit Collect(msg.sender, recipient, tickLower, tickUpper, amount0, amount1);
    }

    // ============================================================
    // BURN — REMOVE LIQUIDITY
    // ============================================================

    function burn(
        int24 tickLower,
        int24 tickUpper,
        uint128 amount
    ) external override lock noDelegateCall returns (uint256 amount0, uint256 amount1) {
        (
            Position.Info storage position,
            int256 amount0Int,
            int256 amount1Int
        ) = _updatePosition(
            msg.sender,
            tickLower,
            tickUpper,
            -amount.toInt128(),
            slot0.tick
        );

        amount0 = uint256(-amount0Int);
        amount1 = uint256(-amount1Int);

        if (amount0 > 0 || amount1 > 0) {
            position.tokensOwed0 += uint128(amount0);
            position.tokensOwed1 += uint128(amount1);
        }

        emit Burn(msg.sender, tickLower, tickUpper, amount, amount0, amount1);
    }

    // ============================================================
    // SWAP
    // ============================================================

    struct SwapCache {
        uint128 liquidityStart;
        uint32 blockTimestamp;
        uint8 feeProtocol;
        uint160 secondsPerLiquidityCumulativeX128;
        int56 tickCumulative;
        bool computedLatestObservation;
    }

    struct SwapState {
        int256 amountSpecifiedRemaining;
        int256 amountCalculated;
        uint160 sqrtPriceX96;
        int24 tick;
        uint256 feeGrowthGlobalX128;
        uint128 protocolFee;
        uint128 liquidity;
    }

    struct StepComputations {
        uint160 sqrtPriceStartX96;
        int24 tickNext;
        bool initialized;
        uint160 sqrtPriceNextX96;
        uint256 amountIn;
        uint256 amountOut;
        uint256 feeAmount;
    }

    function swap(
        address recipient,
        bool zeroForOne,
        int256 amountSpecified,
        uint160 sqrtPriceLimitX96,
        bytes calldata data
    ) external override noDelegateCall returns (int256 amount0, int256 amount1) {
        require(amountSpecified != 0, "KortanaPool: ZERO_AMOUNT");

        Slot0 memory slot0Start = slot0;

        require(slot0Start.unlocked, "KortanaPool: LOCKED");

        require(
            zeroForOne
                ? sqrtPriceLimitX96 < slot0Start.sqrtPriceX96 &&
                    sqrtPriceLimitX96 > TickMath.MIN_SQRT_RATIO
                : sqrtPriceLimitX96 > slot0Start.sqrtPriceX96 &&
                    sqrtPriceLimitX96 < TickMath.MAX_SQRT_RATIO,
            "KortanaPool: INVALID_PRICE_LIMIT"
        );

        slot0.unlocked = false;

        SwapCache memory cache = SwapCache({
            liquidityStart: liquidity,
            blockTimestamp: _blockTimestamp(),
            feeProtocol: zeroForOne
                ? (slot0Start.feeProtocol % 16)
                : (slot0Start.feeProtocol >> 4),
            secondsPerLiquidityCumulativeX128: 0,
            tickCumulative: 0,
            computedLatestObservation: false
        });

        bool exactInput = amountSpecified > 0;

        SwapState memory state = SwapState({
            amountSpecifiedRemaining: amountSpecified,
            amountCalculated: 0,
            sqrtPriceX96: slot0Start.sqrtPriceX96,
            tick: slot0Start.tick,
            feeGrowthGlobalX128: zeroForOne
                ? feeGrowthGlobal0X128
                : feeGrowthGlobal1X128,
            protocolFee: 0,
            liquidity: cache.liquidityStart
        });

        while (
            state.amountSpecifiedRemaining != 0 &&
            state.sqrtPriceX96 != sqrtPriceLimitX96
        ) {
            StepComputations memory step;
            step.sqrtPriceStartX96 = state.sqrtPriceX96;

            (step.tickNext, step.initialized) = tickBitmap.nextInitializedTickWithinOneWord(
                state.tick,
                tickSpacing,
                zeroForOne
            );

            if (step.tickNext < TickMath.MIN_TICK) step.tickNext = TickMath.MIN_TICK;
            else if (step.tickNext > TickMath.MAX_TICK) step.tickNext = TickMath.MAX_TICK;

            step.sqrtPriceNextX96 = TickMath.getSqrtRatioAtTick(step.tickNext);

            (
                state.sqrtPriceX96,
                step.amountIn,
                step.amountOut,
                step.feeAmount
            ) = SwapMath.computeSwapStep(
                state.sqrtPriceX96,
                (
                    zeroForOne
                        ? step.sqrtPriceNextX96 < sqrtPriceLimitX96
                        : step.sqrtPriceNextX96 > sqrtPriceLimitX96
                )
                    ? sqrtPriceLimitX96
                    : step.sqrtPriceNextX96,
                state.liquidity,
                state.amountSpecifiedRemaining,
                fee
            );

            if (exactInput) {
                state.amountSpecifiedRemaining -= (step.amountIn + step.feeAmount).toInt256();
                state.amountCalculated = state.amountCalculated - step.amountOut.toInt256();
            } else {
                state.amountSpecifiedRemaining += step.amountOut.toInt256();
                state.amountCalculated =
                    state.amountCalculated +
                    (step.amountIn + step.feeAmount).toInt256();
            }

            if (cache.feeProtocol > 0) {
                uint256 delta = step.feeAmount / cache.feeProtocol;
                step.feeAmount -= delta;
                state.protocolFee += uint128(delta);
            }

            if (state.liquidity > 0) {
                state.feeGrowthGlobalX128 += FullMath.mulDiv(
                    step.feeAmount,
                    FixedPoint128.Q128,
                    state.liquidity
                );
            }

            if (state.sqrtPriceX96 == step.sqrtPriceNextX96) {
                if (step.initialized) {
                    if (!cache.computedLatestObservation) {
                        (
                            cache.tickCumulative,
                            cache.secondsPerLiquidityCumulativeX128
                        ) = observations.observeSingle(
                            cache.blockTimestamp,
                            0,
                            slot0Start.tick,
                            slot0Start.observationIndex,
                            cache.liquidityStart,
                            slot0Start.observationCardinality
                        );
                        cache.computedLatestObservation = true;
                    }
                    int128 liquidityNet = ticks.cross(
                        step.tickNext,
                        zeroForOne ? state.feeGrowthGlobalX128 : feeGrowthGlobal0X128,
                        zeroForOne ? feeGrowthGlobal1X128 : state.feeGrowthGlobalX128,
                        cache.secondsPerLiquidityCumulativeX128,
                        cache.tickCumulative,
                        cache.blockTimestamp
                    );
                    if (zeroForOne) liquidityNet = -liquidityNet;
                    state.liquidity = LiquidityMath.addDelta(
                        state.liquidity,
                        liquidityNet
                    );
                }
                state.tick = zeroForOne ? step.tickNext - 1 : step.tickNext;
            } else if (state.sqrtPriceX96 != step.sqrtPriceStartX96) {
                state.tick = TickMath.getTickAtSqrtRatio(state.sqrtPriceX96);
            }
        }

        if (state.tick != slot0Start.tick) {
            (
                uint16 observationIndex,
                uint16 observationCardinality
            ) = observations.write(
                slot0Start.observationIndex,
                cache.blockTimestamp,
                slot0Start.tick,
                cache.liquidityStart,
                slot0Start.observationCardinality,
                slot0Start.observationCardinalityNext
            );
            (
                slot0.sqrtPriceX96,
                slot0.tick,
                slot0.observationIndex,
                slot0.observationCardinality
            ) = (
                state.sqrtPriceX96,
                state.tick,
                observationIndex,
                observationCardinality
            );
        } else {
            slot0.sqrtPriceX96 = state.sqrtPriceX96;
        }

        if (cache.liquidityStart != state.liquidity) liquidity = state.liquidity;

        if (zeroForOne) {
            feeGrowthGlobal0X128 = state.feeGrowthGlobalX128;
            if (state.protocolFee > 0) protocolFees.token0 += state.protocolFee;
        } else {
            feeGrowthGlobal1X128 = state.feeGrowthGlobalX128;
            if (state.protocolFee > 0) protocolFees.token1 += state.protocolFee;
        }

        (amount0, amount1) = zeroForOne == exactInput
            ? (
                amountSpecified - state.amountSpecifiedRemaining,
                state.amountCalculated
            )
            : (
                state.amountCalculated,
                amountSpecified - state.amountSpecifiedRemaining
            );

        if (zeroForOne) {
            if (amount1 < 0)
                IERC20(token1).transfer(recipient, uint256(-amount1));

            uint256 balance0Before = _balance0();
            IKortanaSwapCallback(msg.sender).kortanaSwapCallback(
                amount0,
                amount1,
                data
            );
            require(
                balance0Before + uint256(amount0) <= _balance0(),
                "KortanaPool: IIA"
            );
        } else {
            if (amount0 < 0)
                IERC20(token0).transfer(recipient, uint256(-amount0));

            uint256 balance1Before = _balance1();
            IKortanaSwapCallback(msg.sender).kortanaSwapCallback(
                amount0,
                amount1,
                data
            );
            require(
                balance1Before + uint256(amount1) <= _balance1(),
                "KortanaPool: IIA"
            );
        }

        emit Swap(
            msg.sender,
            recipient,
            amount0,
            amount1,
            state.sqrtPriceX96,
            state.liquidity,
            state.tick
        );

        slot0.unlocked = true;
    }

    // ============================================================
    // ORACLE
    // ============================================================

    function observe(uint32[] calldata secondsAgos)
        external
        view
        override
        noDelegateCall
        returns (
            int56[] memory tickCumulatives,
            uint160[] memory secondsPerLiquidityCumulativeX128s
        )
    {
        return
            observations.observe(
                _blockTimestamp(),
                secondsAgos,
                slot0.tick,
                slot0.observationIndex,
                liquidity,
                slot0.observationCardinality
            );
    }

    function increaseObservationCardinalityNext(
        uint16 observationCardinalityNext
    ) external override lock noDelegateCall {
        uint16 observationCardinalityNextOld = slot0.observationCardinalityNext;
        uint16 observationCardinalityNextNew = observations.grow(
            observationCardinalityNextOld,
            observationCardinalityNext
        );
        slot0.observationCardinalityNext = observationCardinalityNextNew;
        if (observationCardinalityNextOld != observationCardinalityNextNew) {
            emit IncreaseObservationCardinalityNext(
                observationCardinalityNextOld,
                observationCardinalityNextNew
            );
        }
    }

    // ============================================================
    // FLASH LOANS
    // ============================================================

    function flash(
        address recipient,
        uint256 amount0,
        uint256 amount1,
        bytes calldata data
    ) external override lock noDelegateCall {
        uint128 _liquidity = liquidity;
        require(_liquidity > 0, "KortanaPool: INSUFFICIENT_LIQUIDITY");

        uint256 fee0 = FullMath.mulDivRoundingUp(amount0, fee, 1e6);
        uint256 fee1 = FullMath.mulDivRoundingUp(amount1, fee, 1e6);
        uint256 balance0Before = _balance0();
        uint256 balance1Before = _balance1();

        if (amount0 > 0) IERC20(token0).transfer(recipient, amount0);
        if (amount1 > 0) IERC20(token1).transfer(recipient, amount1);

        IKortanaFlashCallback(msg.sender).kortanaFlashCallback(fee0, fee1, data);

        uint256 balance0After = _balance0();
        uint256 balance1After = _balance1();

        require(
            balance0Before + fee0 <= balance0After,
            "KortanaPool: F0"
        );
        require(
            balance1Before + fee1 <= balance1After,
            "KortanaPool: F1"
        );

        uint256 paid0 = balance0After - balance0Before;
        uint256 paid1 = balance1After - balance1Before;

        if (paid0 > 0) {
            uint8 feeProtocol0 = slot0.feeProtocol % 16;
            uint256 fees0 = feeProtocol0 == 0 ? 0 : paid0 / feeProtocol0;
            if (uint128(fees0) > 0) protocolFees.token0 += uint128(fees0);
            feeGrowthGlobal0X128 += FullMath.mulDiv(
                paid0 - fees0,
                FixedPoint128.Q128,
                _liquidity
            );
        }
        if (paid1 > 0) {
            uint8 feeProtocol1 = slot0.feeProtocol >> 4;
            uint256 fees1 = feeProtocol1 == 0 ? 0 : paid1 / feeProtocol1;
            if (uint128(fees1) > 0) protocolFees.token1 += uint128(fees1);
            feeGrowthGlobal1X128 += FullMath.mulDiv(
                paid1 - fees1,
                FixedPoint128.Q128,
                _liquidity
            );
        }

        emit Flash(msg.sender, recipient, amount0, amount1, paid0, paid1);
    }

    // ============================================================
    // PROTOCOL FEE COLLECTION
    // ============================================================

    function collectProtocol(
        address recipient,
        uint128 amount0Requested,
        uint128 amount1Requested
    ) external override lock onlyFactoryOwner returns (uint128 amount0, uint128 amount1) {
        amount0 = amount0Requested > protocolFees.token0
            ? protocolFees.token0
            : amount0Requested;
        amount1 = amount1Requested > protocolFees.token1
            ? protocolFees.token1
            : amount1Requested;

        if (amount0 > 0) {
            if (amount0 == protocolFees.token0) amount0--;
            protocolFees.token0 -= amount0;
            IERC20(token0).transfer(recipient, amount0);
        }
        if (amount1 > 0) {
            if (amount1 == protocolFees.token1) amount1--;
            protocolFees.token1 -= amount1;
            IERC20(token1).transfer(recipient, amount1);
        }

        emit CollectProtocol(msg.sender, recipient, amount0, amount1);
    }

    // ============================================================
    // INTERNAL HELPERS
    // ============================================================

    function _blockTimestamp() internal view returns (uint32) {
        return uint32(block.timestamp);
    }

    function _balance0() private view returns (uint256) {
        return IERC20(token0).balanceOf(address(this));
    }

    function _balance1() private view returns (uint256) {
        return IERC20(token1).balanceOf(address(this));
    }

    function _updatePosition(
        address owner,
        int24 tickLower,
        int24 tickUpper,
        int128 liquidityDelta,
        int24 tick
    ) private returns (
        Position.Info storage position,
        int256 amount0,
        int256 amount1
    ) {
        bytes32 key = keccak256(abi.encodePacked(owner, tickLower, tickUpper));
        position = positions[key];

        uint256 _feeGrowthGlobal0X128 = feeGrowthGlobal0X128;
        uint256 _feeGrowthGlobal1X128 = feeGrowthGlobal1X128;

        bool flippedLower;
        bool flippedUpper;

        if (liquidityDelta != 0) {
            (
                int56 tickCumulative,
                uint160 secondsPerLiquidityCumulativeX128
            ) = observations.observeSingle(
                _blockTimestamp(),
                0,
                slot0.tick,
                slot0.observationIndex,
                liquidity,
                slot0.observationCardinality
            );

            flippedLower = ticks.update(
                tickLower,
                tick,
                liquidityDelta,
                _feeGrowthGlobal0X128,
                _feeGrowthGlobal1X128,
                secondsPerLiquidityCumulativeX128,
                tickCumulative,
                _blockTimestamp(),
                false,
                maxLiquidityPerTick
            );
            flippedUpper = ticks.update(
                tickUpper,
                tick,
                liquidityDelta,
                _feeGrowthGlobal0X128,
                _feeGrowthGlobal1X128,
                secondsPerLiquidityCumulativeX128,
                tickCumulative,
                _blockTimestamp(),
                true,
                maxLiquidityPerTick
            );

            if (flippedLower) tickBitmap.flipTick(tickLower, tickSpacing);
            if (flippedUpper) tickBitmap.flipTick(tickUpper, tickSpacing);
        }

        (uint256 feeGrowthInside0X128, uint256 feeGrowthInside1X128) = ticks
            .getFeeGrowthInside(
                tickLower,
                tickUpper,
                tick,
                _feeGrowthGlobal0X128,
                _feeGrowthGlobal1X128
            );

        position.update(liquidityDelta, feeGrowthInside0X128, feeGrowthInside1X128);

        if (tick < tickLower) {
            amount0 = SqrtPriceMath.getAmount0Delta(
                TickMath.getSqrtRatioAtTick(tickLower),
                TickMath.getSqrtRatioAtTick(tickUpper),
                liquidityDelta
            );
        } else if (tick < tickUpper) {
            amount0 = SqrtPriceMath.getAmount0Delta(
                slot0.sqrtPriceX96,
                TickMath.getSqrtRatioAtTick(tickUpper),
                liquidityDelta
            );
            amount1 = SqrtPriceMath.getAmount1Delta(
                TickMath.getSqrtRatioAtTick(tickLower),
                slot0.sqrtPriceX96,
                liquidityDelta
            );

            liquidity = LiquidityMath.addDelta(liquidity, liquidityDelta);
        } else {
            amount1 = SqrtPriceMath.getAmount1Delta(
                TickMath.getSqrtRatioAtTick(tickLower),
                TickMath.getSqrtRatioAtTick(tickUpper),
                liquidityDelta
            );
        }
    }
}

contracts/KortanaPoolDeployer.sol.content:
// SPDX-License-Identifier: GPL-2.0-or-later
pragma solidity ^0.8.20;

import "./interfaces/IKortanaPoolDeployer.sol";
import "./KortanaPool.sol";

contract KortanaPoolDeployer is IKortanaPoolDeployer {
    struct Parameters {
        address factory;
        address token0;
        address token1;
        uint24 fee;
        int24 tickSpacing;
    }

    Parameters public override parameters;

    function deploy(
        address factory,
        address token0,
        address token1,
        uint24 fee,
        int24 tickSpacing
    ) internal returns (address pool) {
        parameters = Parameters({
            factory: factory,
            token0: token0,
            token1: token1,
            fee: fee,
            tickSpacing: tickSpacing
        });
        pool = address(new KortanaPool{salt: keccak256(abi.encode(token0, token1, fee))}());
        delete parameters;
    }
}

